import { useState } from 'react';
import { Copy, Check, TrendingUp, TrendingDown, Minus, AlertTriangle, Zap, MessageSquare } from 'lucide-react';
import { sig, recColor, Bar, Chip } from './ds';

/* Compact data cell */
function Cell({ label, value, color, mono, accent }) {
  return (
    <div style={{ padding: '10px 0', borderBottom: '1px solid var(--rule)' }}>
      <p style={{ fontSize: 10.5, fontWeight: 600, color: 'var(--ink-4)', letterSpacing: '0.07em', textTransform: 'uppercase', margin: '0 0 3px' }}>{label}</p>
      <p style={{ fontSize: 15, fontWeight: 600, color: color || (accent ? 'var(--accent)' : 'var(--ink)'), fontFamily: mono ? 'var(--f-data)' : 'var(--f-ui)', margin: 0, letterSpacing: mono ? '0.01em' : 0 }}>
        {value}
      </p>
    </div>
  );
}

function ScoreRow({ label, value, color }) {
  return (
    <div style={{ marginBottom: 10 }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 5 }}>
        <span style={{ fontSize: 12, color: 'var(--ink-3)' }}>{label}</span>
        <span style={{ fontSize: 12, fontWeight: 600, color, fontFamily: 'var(--f-data)' }}>{value}</span>
      </div>
      <Bar value={value} color={color} h={3} />
    </div>
  );
}

export default function ResultCard({ r }) {
  const [copied, setCopied] = useState(false);

  const sc   = sig.color(r.signal);
  const sbg  = sig.bg(r.signal);
  const srule = sig.rule(r.signal);
  const rc   = recColor(r.recommendation);
  const SIcon = r.signal === 'BULLISH' ? TrendingUp : r.signal === 'BEARISH' ? TrendingDown : Minus;
  const signalTone = r.signal === 'BULLISH' ? 'bull' : r.signal === 'BEARISH' ? 'bear' : 'flat';
  const recTone = ['BUY','ACCUMULATE'].includes(r.recommendation) ? 'bull' : r.recommendation === 'SELL' ? 'bear' : 'flat';

  const copy = () => {
    navigator.clipboard.writeText(r.response);
    setCopied(true);
    setTimeout(() => setCopied(false), 2200);
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 0, maxWidth: '100%' }}>

      {/* ══ Header band ══════════════════════════════════════ */}
      <div style={{
        background: sbg,
        border: `1px solid ${srule}`,
        borderRadius: 'var(--r-lg) var(--r-lg) 0 0',
        padding: '22px 22px 18px',
      }}>
        {/* Ticker row */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 12 }}>
          <div>
            <div style={{ display: 'flex', alignItems: 'baseline', gap: 10, marginBottom: 4 }}>
              <h2 style={{
                fontFamily: 'var(--f-data)', fontSize: 30, fontWeight: 600,
                color: 'var(--ink)', letterSpacing: '-0.01em', margin: 0,
              }}>
                {r.ticker}
              </h2>
              <span style={{ fontSize: 11.5, color: 'var(--ink-3)', fontWeight: 400 }}>{r.exchange}</span>
            </div>
            <p style={{ fontSize: 13, color: 'var(--ink-3)', margin: 0 }}>{r.companyName}</p>
          </div>
          <div style={{ textAlign: 'right' }}>
            <p style={{ fontFamily: 'var(--f-data)', fontSize: 28, fontWeight: 600, color: 'var(--ink)', letterSpacing: '-0.02em', margin: 0 }}>
              {r.price}
            </p>
            <p style={{ fontSize: 13, fontWeight: 500, color: r.changePositive ? 'var(--bull)' : 'var(--bear)', margin: '3px 0 0', display: 'flex', alignItems: 'center', gap: 4, justifyContent: 'flex-end' }}>
              <SIcon size={13} strokeWidth={2.5} />
              {r.change}
            </p>
          </div>
        </div>

        {/* Signal row */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 8, flexWrap: 'wrap' }}>
          <Chip tone={signalTone}>{r.signal}</Chip>
          <Chip tone={recTone}>{r.recommendation}</Chip>
          <Chip tone='neutral'>{r.confidence}% confidence</Chip>
          <div style={{ flex: 1, minWidth: 60 }}>
            <Bar value={r.confidence} color={sc} h={3} />
          </div>
        </div>
      </div>

      {/* ══ Target / Support / Resistance ════════════════════ */}
      <div style={{
        display: 'grid', gridTemplateColumns: '1fr 1fr 1fr',
        border: '1px solid var(--rule)', borderTop: 'none',
        background: 'var(--card)',
      }}>
        {[
          { k: 'Target', v: r.targetPrice, c: 'var(--accent)' },
          { k: 'Support', v: r.support || '—', c: 'var(--bull)' },
          { k: 'Resistance', v: r.resistance || '—', c: 'var(--bear)' },
        ].map((item, i) => (
          <div key={i} style={{ padding: '12px 16px', borderRight: i < 2 ? '1px solid var(--rule)' : 'none' }}>
            <p style={{ fontSize: 10.5, fontWeight: 600, color: 'var(--ink-4)', letterSpacing: '0.07em', textTransform: 'uppercase', margin: '0 0 4px' }}>{item.k}</p>
            <p style={{ fontFamily: 'var(--f-data)', fontSize: 16, fontWeight: 600, color: item.c, margin: 0 }}>{item.v}</p>
          </div>
        ))}
      </div>

      {/* ══ Fundamentals + Indicators ════════════════════════ */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', border: '1px solid var(--rule)', borderTop: 'none', background: 'var(--white)' }}>

        {/* Fundamentals */}
        <div style={{ padding: '14px 16px', borderRight: '1px solid var(--rule)' }}>
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 4 }}>
            <p style={{ fontSize: 10.5, fontWeight: 600, color: 'var(--ink-4)', letterSpacing: '0.08em', textTransform: 'uppercase', margin: 0 }}>Fundamentals</p>
            {r.dataSource && (
              <span style={{ fontSize: 9.5, fontWeight: 700, padding: '2px 6px', borderRadius: 3, background: r.dataSource.includes('live') ? 'var(--bull-bg)' : 'var(--flat-bg)', color: r.dataSource.includes('live') ? 'var(--bull)' : 'var(--flat)', border: `1px solid ${r.dataSource.includes('live') ? 'var(--bull-rule)' : 'var(--flat-rule)'}`, letterSpacing: '0.04em', fontFamily: 'var(--f-data)' }}>
                {r.dataSource.includes('live') ? 'LIVE' : 'EST'}
              </span>
            )}
          </div>
          <Cell label='Price' value={r.price} mono color={r.changePositive ? 'var(--bull)' : 'var(--bear)'} />
          <Cell label='P / E Ratio' value={r.peRatio} mono />
          <Cell label='Market Cap' value={r.marketCap} mono />
          <Cell label='52W High' value={r.weekHigh52} mono color='var(--bull)' />
          <Cell label='52W Low' value={r.weekLow52} mono color='var(--bear)' />
          {r.eps && r.eps !== 'N/A' && <Cell label='EPS (TTM)' value={r.eps} mono />}
          {r.dividendYield && r.dividendYield !== 'N/A' && <Cell label='Div. Yield' value={r.dividendYield} mono />}
          {r.beta && r.beta !== 'N/A' && <Cell label='Beta' value={r.beta} mono />}
          {r.volume && r.volume !== 'N/A' && <Cell label="Today's Vol" value={r.volume} mono />}
          {r.lastUpdated && (
            <p style={{ fontSize: 10, color: 'var(--ink-5)', marginTop: 8, fontFamily: 'var(--f-data)' }}>Updated {r.lastUpdated}</p>
          )}
        </div>

        {/* Scores */}
        <div style={{ padding: '14px 16px' }}>
          <p style={{ fontSize: 10.5, fontWeight: 600, color: 'var(--ink-4)', letterSpacing: '0.08em', textTransform: 'uppercase', marginBottom: 12 }}>Indicators</p>
          <ScoreRow label='Momentum'      value={r.momentumScore}      color='var(--bull)' />
          <ScoreRow label='Sentiment'     value={r.sentimentScore}     color='var(--info)' />
          <ScoreRow label='Volume'        value={r.volumeScore}        color='#7c3aed' />
          <ScoreRow label='Institutional' value={r.institutionalScore} color='var(--flat)' />
          {r.technicalScore   && <ScoreRow label='Technical'   value={r.technicalScore}   color='var(--info)' />}
          {r.fundamentalScore && <ScoreRow label='Fundamental' value={r.fundamentalScore} color='var(--bull)' />}
        </div>
      </div>

      {/* ══ Risk / Catalyst ══════════════════════════════════ */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', border: '1px solid var(--rule)', borderTop: 'none' }}>
        <div style={{ padding: '14px 16px', background: 'var(--bear-bg)', borderRight: '1px solid var(--bear-rule)' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 8 }}>
            <AlertTriangle size={13} color='var(--bear)' strokeWidth={2} />
            <span style={{ fontSize: 10.5, fontWeight: 700, color: 'var(--bear)', letterSpacing: '0.07em', textTransform: 'uppercase' }}>Key risk</span>
          </div>
          <p style={{ fontSize: 13, color: 'var(--ink-2)', lineHeight: 1.6, margin: 0 }}>{r.keyRisk}</p>
        </div>
        <div style={{ padding: '14px 16px', background: 'var(--bull-bg)' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 8 }}>
            <Zap size={13} color='var(--bull)' strokeWidth={2} />
            <span style={{ fontSize: 10.5, fontWeight: 700, color: 'var(--bull)', letterSpacing: '0.07em', textTransform: 'uppercase' }}>Key catalyst</span>
          </div>
          <p style={{ fontSize: 13, color: 'var(--ink-2)', lineHeight: 1.6, margin: 0 }}>{r.catalyst}</p>
        </div>
      </div>

      {/* ══ Client intent ════════════════════════════════════ */}
      {r.summary && (
        <div style={{
          border: '1px solid var(--rule)', borderTop: 'none',
          padding: '15px 18px', background: 'var(--white)',
        }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 9 }}>
            <MessageSquare size={13} color='var(--ink-3)' strokeWidth={1.8} />
            <span style={{ fontSize: 10.5, fontWeight: 600, color: 'var(--ink-3)', letterSpacing: '0.07em', textTransform: 'uppercase' }}>
              Client intent
            </span>
          </div>
          <p style={{ fontSize: 13, color: 'var(--ink-2)', lineHeight: 1.7, margin: 0, fontStyle: 'italic' }}>
            {r.summary}
          </p>
        </div>
      )}

      {/* ══ Analyst response ═════════════════════════════════ */}
      <div style={{
        border: '1px solid var(--rule)', borderTop: 'none',
        borderRadius: '0 0 var(--r-lg) var(--r-lg)',
        overflow: 'hidden', background: 'var(--white)',
      }}>
        <div style={{
          padding: '10px 16px',
          borderBottom: '1px solid var(--rule)',
          display: 'flex', justifyContent: 'space-between', alignItems: 'center',
          background: 'var(--paper)',
        }}>
          <span style={{ fontSize: 10.5, fontWeight: 700, color: 'var(--ink-3)', letterSpacing: '0.08em', textTransform: 'uppercase' }}>
            Read to client
          </span>
          <button
            onClick={copy}
            style={{
              display: 'flex', alignItems: 'center', gap: 5,
              padding: '4px 10px',
              background: copied ? 'var(--bull-bg)' : 'var(--white)',
              border: `1px solid ${copied ? 'var(--bull-rule)' : 'var(--rule-2)'}`,
              borderRadius: 'var(--r)', fontSize: 11.5, fontWeight: 500,
              color: copied ? 'var(--bull)' : 'var(--ink-3)',
              cursor: 'pointer', transition: 'all 0.2s', fontFamily: 'var(--f-ui)',
            }}
          >
            {copied ? <Check size={12} /> : <Copy size={12} />}
            {copied ? 'Copied' : 'Copy'}
          </button>
        </div>

        <div style={{ padding: '18px 20px' }}>
          <div style={{ borderLeft: '2px solid var(--accent-2)', paddingLeft: 14 }}>
            <p style={{
              fontFamily: 'var(--f-display)', fontSize: 15, fontStyle: 'italic',
              color: 'var(--ink-2)', lineHeight: 1.9, margin: 0,
            }}>
              "{r.response}"
            </p>
          </div>
        </div>
      </div>

    </div>
  );
}
